-- ============================================================
-- addr3: 行政区划树（省/市/区/街道等层级地址）
-- id 为区划编码；pid 指向父级 id，顶级为 0
-- ext_path 为从根到当前的 id 路径；longitude/latitude 为中心点经纬度
-- 无库级外键，由业务/导入脚本保证一致性
-- ============================================================
CREATE TABLE IF NOT EXISTS "public"."addr3" (
    "id"        INT8 PRIMARY KEY,                          -- 区划编码
    "pid"       INT8 NOT NULL DEFAULT 0,                   -- 父级 id，0 表示顶级
    "deep"      INT2 NOT NULL,                             -- 层级深度：0省 1市 2区县 ...
    "name"      VARCHAR(100) NOT NULL,                     -- 名称
    "ext_path"  VARCHAR(500) NOT NULL,                   -- 扩展路径，如 110000,110100,110101
    "longitude" NUMERIC(9, 6),                           -- 经度
    "latitude"  NUMERIC(8, 6)                            -- 纬度
);

CREATE INDEX IF NOT EXISTS "idx_public_addr3_pid"
    ON "public"."addr3" ("pid");

CREATE INDEX IF NOT EXISTS "idx_public_addr3_deep"
    ON "public"."addr3" ("deep");

CREATE INDEX IF NOT EXISTS "idx_public_addr3_ext_path"
    ON "public"."addr3" ("ext_path");

CREATE INDEX IF NOT EXISTS "idx_public_addr3_lat_lng"
    ON "public"."addr3" ("latitude", "longitude")
    WHERE "latitude" IS NOT NULL AND "longitude" IS NOT NULL;




